# Google Python Style — Key Rules

# CORRECT: Descriptive names
def calculate_average_response_time(timings: list[float]) -> float:
    return sum(timings) / len(timings)

# WRONG: Abbreviations
def calc_avg_resp(t):  # what is t?
    return sum(t) / len(t)

# CORRECT: Type annotations mandatory
UserDict: TypeAlias = dict[str, Any]

def fetch_user(user_id: int, db: Database) -> UserDict | None:
    return db.query('SELECT * FROM users WHERE id = ?', user_id).one_or_none()

# CORRECT: Exceptions are exceptional, not control flow
# WRONG: using try/except for control flow

# CORRECT: Explicit over implicit
def process(data: bytes, encoding: str = 'utf-8') -> str:
    return data.decode(encoding)

