# === Observability pattern ===
import time
import functools
import logging

logger = logging.getLogger(__name__)

def observe(service: str):
    '''Decorator to add metrics and logging to a function.'''
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            start = time.perf_counter()
            try:
                result = func(*args, **kwargs)
                elapsed = time.perf_counter() - start
                # In production: emit metric (latency, success)
                logger.info('%s.%s: %.4fs', service, func.__name__, elapsed)
                return result
            except Exception as e:
                elapsed = time.perf_counter() - start
                logger.exception('%s.%s: error after %.4fs', service, func.__name__, elapsed)
                raise
        return wrapper
    return decorator

