# === Graceful shutdown ===
import signal

class Server:
    def run(self):
        self._running = True
        signal.signal(signal.SIGTERM, self._shutdown)
        while self._running:
            self.process_next()

    def _shutdown(self, signum, frame):
        logger.info('shutting down gracefully')
        self._running = False
        self.cleanup()
